/***** Code Node — Format Slack + Email Messages for STP Requests *****/

const rec = $input.first().json.body.records[0]; // webhook payload root

function clean(s){ return String(s || "").trim(); }

// Extract fields from webhook payload
const role = clean(rec.role?.[0] || "Unspecified Role");
const client = clean(rec.clients?.[0] || "Unknown Client");
const jdLink = clean(rec.jd_profile?.[0] || "");
const employmentType = clean(rec.employment_type || "N/A");
const targetStartDate = clean(rec.target_start_date || "N/A");
const company = clean(rec.company?.[0] || "N/A");
const rate = rec.final_client_rate ? `$${rec.final_client_rate}/hr` : "N/A";
const hardRequirement = clean(rec.hard_requirement || "N/A");
const stpCode = clean(rec.stp_code || "N/A");

// ---------- SLACK BLOCKS ----------
const messageBlocks = [];
messageBlocks.push({
  type: "section",
  text: { type: "mrkdwn", text: `*New STP Request — ${role}*` }
});
messageBlocks.push({ type: "divider" });

const jdText = jdLink ? `here is the link to the *<${jdLink}|JD>.*` : `no JD link available.`;
messageBlocks.push({
  type: "section",
  text: {
    type: "mrkdwn",
    text: `Hi <!here>,\n\nA new sourcing request has been submitted for *${role}* with *${client}*.\nFor your reference, ${jdText}`
  }
});

messageBlocks.push({
  type: "section",
  fields: [
    { type: "mrkdwn", text: `*Client:* ${client}` },
    { type: "mrkdwn", text: `*Company:* ${company}` },
    { type: "mrkdwn", text: `*Employment Type:* ${employmentType}` },
    { type: "mrkdwn", text: `*Rate:* ${rate}` },
    { type: "mrkdwn", text: `*Target Start Date:* ${targetStartDate}` },
    { type: "mrkdwn", text: `*Hard Requirement:* ${hardRequirement}` },
  ]
});
messageBlocks.push({ type: "divider" });
messageBlocks.push({
  type: "section",
  text: { type: "mrkdwn", text: `Please use the reference code *${stpCode}* for tracking.\nThank you!` }
});

// ---------- EMAIL BODY ----------
const jdLinkHTML = jdLink
  ? `<a href="${jdLink}" target="_blank">Job Description</a>`
  : `Job Description (link unavailable)`;

const emailBody = `
<p>Hi TA,</p>

<p>
We would like to formally request assistance in sourcing a
<strong>${role}</strong> for <strong>${client}</strong>.
</p>

<p>
For your reference and review, here is the link to the ${jdLinkHTML}.
</p>

<table style="border-collapse:collapse; margin-top:10px; margin-bottom:10px;">
  <tr>
    <td style="padding:3px 16px 3px 0; vertical-align:top; white-space:nowrap;"><strong>Employment Type:</strong></td>
    <td style="padding:3px 0;">${employmentType}</td>
  </tr>
  <tr>
    <td style="padding:3px 16px 3px 0; vertical-align:top; white-space:nowrap;"><strong>Company:</strong></td>
    <td style="padding:3px 0;">${company}</td>
  </tr>
  <tr>
    <td style="padding:3px 16px 3px 0; vertical-align:top; white-space:nowrap;"><strong>Client Rate:</strong></td>
    <td style="padding:3px 0;">${rate}</td>
  </tr>
  <tr>
    <td style="padding:3px 16px 3px 0; vertical-align:top; white-space:nowrap;"><strong>Start Date:</strong></td>
    <td style="padding:3px 0;">${targetStartDate}</td>
  </tr>
  <tr>
    <td style="padding:3px 16px 3px 0; vertical-align:top; white-space:nowrap;"><strong>Hard Requirement:</strong></td>
    <td style="padding:3px 0;">${hardRequirement}</td>
  </tr>
</table>

<p>Please use the reference code <strong>${stpCode}</strong> for easy tracking and documentation.</p>

<p>
Should you have any questions or need additional details, feel free to reach out at your convenience.
</p>

<p>Thank you!</p>

<p>Best regards,<br>
<strong>Placements Team</strong><br>
<span style="color:#888;">Scale Virtually</span>
</p>
`;

// ---------- OUTPUT ----------
return [{
  json: {
    slack: {
      text: `New STP Request — ${role}`,
      channelId: "C09ESC12MA5",
      blocks: messageBlocks,
      unfurl_links: false,
      unfurl_media: false
    },
    emailSubject: `New STP Request — ${role}`,
    emailBody
  }
}];

